--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `products` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `name_ar` varchar(255) DEFAULT NULL,
  `slug` varchar(255) NOT NULL,
  `type` varchar(255) NOT NULL DEFAULT 'simple',
  `sku` varchar(255) NOT NULL,
  `short_description` text DEFAULT NULL,
  `short_description_ar` text DEFAULT NULL,
  `description` text DEFAULT NULL,
  `description_ar` text DEFAULT NULL,
  `price` decimal(10,2) NOT NULL,
  `sale_price` decimal(10,2) DEFAULT NULL,
  `is_sale_enable` tinyint(1) NOT NULL DEFAULT 0,
  `sale_starts_at` timestamp NULL DEFAULT NULL,
  `sale_expired_at` timestamp NULL DEFAULT NULL,
  `cost_price` decimal(10,2) DEFAULT NULL,
  `stock_quantity` int(11) NOT NULL DEFAULT 0,
  `min_stock_alert` int(11) NOT NULL DEFAULT 5,
  `weight` decimal(8,2) DEFAULT NULL,
  `weight_unit` varchar(10) NOT NULL DEFAULT 'kg',
  `unit` varchar(255) DEFAULT NULL,
  `brand_id` bigint(20) unsigned DEFAULT NULL,
